import React, { useState, useEffect } from 'react';
import { auth, db } from './Firebase';
import { collection, addDoc, getDocs, updateDoc, doc, query, orderBy, onSnapshot } from 'firebase/firestore';
import './Home.css';
import './Forum.css';

const Forum = () => {
  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState('');
  const [replyContent, setReplyContent] = useState({});
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const unsubscribeAuth = auth.onAuthStateChanged((currentUser) => {
      if (currentUser) {
        setUser({
          uid: currentUser.uid,
          displayName: currentUser.displayName || currentUser.email,
          email: currentUser.email,
          photoURL: currentUser.photoURL
        });
      } else {
        setUser(null);
      }
    });

    const unsubscribePosts = subscribeToForumPosts();

    return () => {
      unsubscribeAuth();
      unsubscribePosts();
    };
  }, []);

  const subscribeToForumPosts = () => {
    const postsQuery = query(
      collection(db, 'forum'),
      orderBy('createdAt', 'desc')
    );

    return onSnapshot(postsQuery, (snapshot) => {
      const updatedPosts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
        replies: doc.data().replies || [],
        likes: doc.data().likes || [],
        dislikes: doc.data().dislikes || []
      }));
      setPosts(updatedPosts);
      setIsLoading(false);
    });
  };

  const handlePostSubmit = async (e) => {
    e.preventDefault();
    if (!user) {
      alert('Please log in to post');
      return;
    }

    if (newPost.trim()) {
      try {
        const postData = {
          content: newPost,
          author: {
            uid: user.uid,
            displayName: user.displayName,
            photoURL: user.photoURL
          },
          createdAt: new Date().toISOString(),
          replies: [],
          likes: [],
          dislikes: []
        };

        await addDoc(collection(db, 'forum'), postData);
        setNewPost('');
      } catch (error) {
        console.error('Error adding post:', error);
        alert('Failed to add post. Please try again.');
      }
    }
  };

  const handleReplySubmit = async (postId) => {
    if (!user) {
      alert('Please log in to reply');
      return;
    }

    const replyText = replyContent[postId];
    if (!replyText?.trim()) return;

    try {
      const postRef = doc(db, 'forum', postId);
      const post = posts.find(p => p.id === postId);

      const newReply = {
        content: replyText,
        author: {
          uid: user.uid,
          displayName: user.displayName,
          photoURL: user.photoURL
        },
        createdAt: new Date().toISOString()
      };

      await updateDoc(postRef, {
        replies: [...(post.replies || []), newReply]
      });

      setReplyContent(prev => ({
        ...prev,
        [postId]: ''
      }));
    } catch (error) {
      console.error('Error adding reply:', error);
      alert('Failed to add reply. Please try again.');
    }
  };

  const handleReaction = async (postId, reactionType) => {
    if (!user) {
      alert('Please log in to react');
      return;
    }

    try {
      const postRef = doc(db, 'forum', postId);
      const post = posts.find(p => p.id === postId);

      const userReacted = post[reactionType].includes(user.uid);
      const oppositeType = reactionType === 'likes' ? 'dislikes' : 'likes';

      let updatedLikes = [...post.likes];
      let updatedDislikes = [...post.dislikes];

      if (reactionType === 'likes') {
        if (userReacted) {
          updatedLikes = updatedLikes.filter(id => id !== user.uid);
        } else {
          updatedLikes.push(user.uid);
          updatedDislikes = updatedDislikes.filter(id => id !== user.uid);
        }
      } else {
        if (userReacted) {
          updatedDislikes = updatedDislikes.filter(id => id !== user.uid);
        } else {
          updatedDislikes.push(user.uid);
          updatedLikes = updatedLikes.filter(id => id !== user.uid);
        }
      }

      await updateDoc(postRef, {
        likes: updatedLikes,
        dislikes: updatedDislikes
      });
    } catch (error) {
      console.error('Error updating reaction:', error);
      alert('Failed to update reaction. Please try again.');
    }
  };

  if (isLoading) {
    return <div className="loading">Loading forum posts...</div>;
  }

  return (
    <div className="forum-container">
      <div className="forum-header">
        <h1>Wildlife Conservation Forum</h1>
        <p>Join the conversation about wildlife conservation and share your thoughts!</p>
      </div>

      {user ? (
        <div className="post-form">
          <form onSubmit={handlePostSubmit}>
            <textarea
              value={newPost}
              onChange={(e) => setNewPost(e.target.value)}
              placeholder="Share your thoughts..."
              rows="4"
              required
            />
            <button type="submit" className="submit-post-button">Post</button>
          </form>
        </div>
      ) : (
        <div className="login-prompt">
          <p>Please log in to participate in the forum.</p>
        </div>
      )}

      <div className="forum-posts">
        {posts.map((post) => (
          <div key={post.id} className="post">
            <div className="post-content">
              <div className="post-header">
                <img 
                  src={post.author.photoURL || '/default-avatar.png'} 
                  alt="Profile" 
                  className="author-avatar"
                />
                <div className="post-info">
                  <strong>{post.author.displayName}</strong>
                  <span className="timestamp">{new Date(post.createdAt).toLocaleString()}</span>
                </div>
              </div>
              <p>{post.content}</p>

              <div className="post-actions">
                <button 
                  onClick={() => handleReaction(post.id, 'likes')}
                  className={post.likes.includes(user?.uid) ? 'active' : ''}
                >
                  👍 {post.likes.length}
                </button>
                <button 
                  onClick={() => handleReaction(post.id, 'dislikes')}
                  className={post.dislikes.includes(user?.uid) ? 'active' : ''}
                >
                  👎 {post.dislikes.length}
                </button>
              </div>

              {post.replies.length > 0 && (
                <div className="replies">
                  {post.replies.map((reply, index) => (
                    <div key={index} className="reply">
                      <div className="reply-header">
                        <img 
                          src={reply.author.photoURL || '/default-avatar.png'} 
                          alt="Profile" 
                          className="author-avatar small"
                        />
                        <div className="reply-info">
                          <strong>{reply.author.displayName}</strong>
                          <span className="timestamp">{new Date(reply.createdAt).toLocaleString()}</span>
                        </div>
                      </div>
                      <p>{reply.content}</p>
                    </div>
                  ))}
                </div>
              )}

              {user && (
                <div className="reply-form">
                  <textarea
                    value={replyContent[post.id] || ''}
                    onChange={(e) => setReplyContent(prev => ({
                      ...prev,
                      [post.id]: e.target.value
                    }))}
                    placeholder="Write a reply..."
                    rows="2"
                  />
                  <button 
                    onClick={() => handleReplySubmit(post.id)}
                    className="submit-reply-button"
                  >
                    Reply
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Forum;
